import { 手勢, 指寬 } from './zhi.js';
import { 堅實心合掌, 虛心合掌, 未敷蓮合掌, 初割蓮合掌, 金剛合掌, 顯露合掌, 持水合掌, 反叉合掌, 反背互相著合掌, 橫拄指合掌, 覆手向下合掌, 覆手合掌, } from './hezhang.js';
function 拳基(bi, x, z, 比, 相) {
    const s = 手勢(bi, x, z, 比);
    const 鈎 = 相.鈎 ?? 0;
    // 豎指先落：自脊後而出，拳身蔽其根（畫其可見——遮擋之序）
    s.衣(() => {
        if (相.豎頭) {
            const 鏈 = s.指(-1.6, -1.3, -Math.PI / 2 + 0.06, [1.9, 1.5, 1.05], [0, 0.34 * 鈎, 0.52 * 鈎]);
            s.畫(鏈, 指寬.根, 指寬.梢, { 紋: true, 甲: Math.abs(比) >= 2 });
        }
        if (相.豎小) {
            const 鏈 = s.指(1.6, -1.15, -Math.PI / 2 - 0.06, [1.5, 1.1, 0.8], [0, -0.3 * 鈎, -0.46 * 鈎]);
            s.畫(鏈, 指寬.小根, 指寬.小梢, { 紋: true, 甲: Math.abs(比) >= 2 });
        }
    });
    // 拳郭：先蔽後勒——圓渾之塊（圓滿之相——弧不露稜）
    s.蔽([[-2.55, -1.2], [-1.7, -2.05], [0.4, -2.2], [1.6, -1.6], [2.5, -1.15], [2.8, -0.3],
        [2.7, 0.5], [2.6, 1.4], [1.9, 2.05], [0.9, 2.25], [-0.5, 2.5], [-1.8, 2.3],
        [-2.3, 1.5], [-2.65, 0.4]]);
    s.骨(() => {
        s.M(-2.55, -1.2);
        s.C(-1.7, -2.05, 0.4, -2.2, 1.6, -1.6);
        s.C(2.5, -1.15, 2.8, -0.3, 2.7, 0.5);
        s.C(2.6, 1.4, 1.9, 2.05, 0.9, 2.25);
        s.C(-0.5, 2.5, -1.8, 2.3, -2.3, 1.5);
        s.Qk(-2.65, 0.4, -2.55, -1.2);
        s.S();
    });
    // 掌骨之峰：脊上四丘（丘足踏脊，弧不越郭）
    s.細(() => {
        for (const [ka, kb] of [[-1.72, -1.28], [-0.6, -1.52], [0.55, -1.48], [1.45, -1.12]])
            s.弧(ka, kb, 0.3, Math.PI * 1.2, Math.PI * 1.85);
    });
    // 四指之列（左頭右小——右拳背觀，拇在左）：豎者已先落，餘者屈為柱
    const 列 = [['頭', -1.8], ['中', -0.7], ['無名', 0.4], ['小', 1.45]];
    s.衣(() => {
        for (const [名, kx] of 列) {
            if ((相.豎頭 && 名 === '頭') || (相.豎小 && 名 === '小'))
                continue;
            // 屈指之柱：本節見面，中節內折（畫其可見）
            const 鏈 = s.指(kx, -1.3, Math.PI / 2 - 0.07, [1.5, 1.15], [0, 0.22]);
            s.畫(鏈, 0.95, 0.86, { 紋: true });
            s.細(() => { s.弧(kx - 0.1, 1.55, 0.28, Math.PI * 0.15, Math.PI * 0.85); });
        }
        if (相.拇 === '入') {
            // 大指入掌：拇丘之腹與頭指覆拇之折——拇不可見
            s.M(-2.45, 0.55);
            s.Qk(-2.05, 1.6, -1.15, 1.95);
            s.S();
            s.細(() => { s.M(-1.9, 0.0); s.Qk(-1.68, 0.75, -1.82, 1.4); s.S(); });
        }
        else {
            // 大指押中指無名指甲上：橫過拳前
            const 拇 = s.指(-2.35, 0.6, -0.22, [1.6, 1.38], [0, 0.3]);
            s.畫(拇, 指寬.拇根, 指寬.拇梢, { 紋: true, 甲: Math.abs(比) >= 2 });
        }
    });
    // 腕：近直而相隨
    s.骨(() => { s.M(-1.7, 2.35); s.L(-1.82, 3.6); s.S(); s.M(1.5, 2.3); s.L(1.62, 3.55); s.S(); });
    s.細(() => { s.M(-1.45, 2.6); s.Qk(-0.2, 3.0, 1.2, 2.6); s.S(); });
}
// ═══ 六種拳（大日經疏卷十三，疏文原數六） ════════════════════════════════════
// 金剛拳：大指入於掌中，餘四指握之
export function 金剛拳(bi, x, z, 比 = 1) {
    拳基(bi, x, z, 比, { 拇: '入' });
}
// 忿怒拳：金剛拳而豎頭指小指，二鈎相向
export function 忿怒拳(bi, x, z, 比 = 1) {
    拳基(bi, x, z, 比, { 拇: '壓', 豎頭: true, 豎小: true, 鈎: 0.55 });
}
// 蓮華拳（胎拳）：四指握，大指壓頭指外側節（壓式；立式並傳〔待核定本〕）
export function 蓮華拳(bi, x, z, 比 = 1) {
    const s = 手勢(bi, x, z, 比);
    // 先蔽後勒：側觀（拇側向觀者）——背之脊自腕隆至頭指本節，頭指捲為螺
    s.蔽([[-2.6, -1.4], [-1.4, -2.05], [0.3, -2.1], [1.55, -1.5], [2.45, -1.05], [2.75, -0.15],
        [2.35, 0.6], [1.95, 1.2], [1.2, 1.35], [0.75, 1.9], [-0.1, 2.2], [-1.1, 2.1],
        [-1.8, 1.65], [-2.7, 1.0], [-3.0, -0.2]]);
    s.骨(() => {
        s.M(-2.6, -1.4);
        s.C(-1.4, -2.05, 0.3, -2.1, 1.55, -1.5);
        s.C(2.45, -1.05, 2.75, -0.15, 2.35, 0.6);
        s.Qk(1.95, 1.2, 1.2, 1.35);
        s.S();
        // 掌根至小指緣：下緣圓滿，收就螺尾
        s.M(-2.6, -1.3);
        s.C(-3.0, -0.2, -2.7, 1.0, -1.8, 1.65);
        s.C(-1.1, 2.1, -0.1, 2.2, 0.75, 1.9);
        s.Qk(1.05, 1.78, 1.2, 1.35);
        s.S();
    });
    s.衣(() => {
        // 頭指之螺：中節末節內旋一線（畫其可見）
        s.M(1.6, -0.7);
        s.C(2.1, -0.3, 2.1, 0.35, 1.6, 0.7);
        s.Qk(1.15, 0.95, 0.7, 0.85);
        s.S();
        // 中指本節：頭指之後微出
        s.逸(() => { s.M(0.9, -1.9); s.Qk(1.7, -1.72, 2.2, -1.15); s.S(); });
        // 大指：自拇丘斜上，末節壓頭指外側節
        const 拇 = s.指(-1.1, 1.3, -0.9, [1.9, 1.5], [0, 0.65]);
        s.畫(拇, 指寬.拇根, 指寬.拇梢, { 紋: true, 甲: Math.abs(比) >= 2 });
    });
    // 節紋：頭指本節之折
    s.細(() => { s.M(2.15, -1.0); s.Qk(2.42, -0.6, 2.3, -0.2); s.S(); });
    // 腕：左出二線近平
    s.骨(() => { s.M(-2.6, -1.4); s.L(-3.75, -1.5); s.S(); s.M(-2.7, 0.9); s.L(-3.85, 1.0); s.S(); });
    s.細(() => { s.M(-2.9, -0.95); s.Qk(-3.15, -0.1, -2.95, 0.65); s.S(); });
}
// ── 縛基：兩掌相叉之郭（內縛外縛共之） ──────────────────────────────────────
function 縛郭(bi, x, z, 比) {
    for (const 鏡 of [-1, 1]) {
        const s = 手勢(bi, x, z, 比, 鏡);
        s.骨(() => {
            s.M(4.35, 0.4);
            s.C(4.1, -0.9, 3.0, -1.75, 1.55, -1.8);
            s.Qk(0.7, -1.8, 0.08, -1.42);
            s.S();
            s.M(4.35, 0.4);
            s.C(3.9, 1.7, 2.3, 2.6, 0.05, 2.65);
            s.S();
        });
        s.骨(() => { s.M(4.3, 0.15); s.L(5.5, 0.05); s.S(); s.M(3.7, 1.95); s.L(4.8, 2.25); s.S(); });
        s.細(() => { s.M(4.45, 0.55); s.Qk(4.75, 1.15, 4.35, 1.8); s.S(); });
    }
}
// 內縛：十指交於掌內——外惟見兩背之丘與本節入縫之列
export function 內縛(bi, x, z, 比 = 1) {
    縛郭(bi, x, z, 比);
    const 中 = 手勢(bi, x, z, 比);
    中.細(() => { 中.M(0, -1.35); 中.Qk(0.06, -0.3, 0, 0.78); 中.S(); });
    // 本節之列：左右各四，斜沒入中縫（左先右後，右壓左）
    for (const 鏡 of [-1, 1]) {
        const s = 手勢(bi, x, z, 比, 鏡);
        s.衣(() => {
            for (const [根a, 根b] of [[3.2, -1.12], [2.35, -1.45], [1.5, -1.58], [0.72, -1.5]]) {
                const 鏈 = s.指(根a, 根b, Math.PI - 1.05, [0.9, 0.8], [0, 0.3]);
                s.畫(鏈, 0.88, 0.78, { 紋: false });
            }
        });
    }
}
// 外縛：十指交於掌外，指頭露外——八指相叉橫臥兩背，二拇交於下
export function 外縛(bi, x, z, 比 = 1) {
    縛郭(bi, x, z, 比);
    const L = 手勢(bi, x, z, 比, -1), R = 手勢(bi, x, z, 比, 1);
    // 相叉之織：八指人字相錯於兩背之上，梢向彼側而沒——逐對一左一右相壓
    const 列 = [
        [0.55, -1.5, 0.42, [1.75, 1.35], 1.0, 0.78],
        [1.55, -1.32, 0.55, [1.8, 1.4], 1.05, 0.8],
        [2.5, -0.95, 0.68, [1.6, 1.25], 0.9, 0.68],
    ];
    for (let i = 0; i < 列.length; i++) {
        const [根a, 根b, 斜, 長, w0, w1] = 列[i];
        for (const s of i % 2 ? [R, L] : [L, R]) {
            s.衣(() => {
                const 鏈 = s.指(根a, 根b, Math.PI - 斜, 長, [0, 0.28]);
                s.畫(鏈, w0, w1, { 紋: false, 甲: Math.abs(比) >= 2 });
            });
        }
    }
    // 小指之梢：外緣微露一對（畫其可見，弗使網密）
    for (const s of [L, R]) {
        s.衣(() => {
            const 鏈 = s.指(3.2, -0.5, Math.PI - 0.8, [1.15, 0.9], []);
            s.畫(鏈, 0.78, 0.6, { 紋: false, 甲: Math.abs(比) >= 2 });
        });
    }
    // 二拇：交於下緣，右壓左
    for (const s of [L, R]) {
        s.衣(() => {
            const 拇 = s.指(-2.55, 1.6, -0.35, [1.5, 1.15], [0, 0.26]);
            s.畫(拇, 指寬.拇根, 指寬.拇梢, { 紋: false, 甲: Math.abs(比) >= 2 });
        });
    }
}
// ── 豎拳直指之核：下拳豎一指、上拳握之（智拳印・如來拳共之）
//    飾＝false 則略腕（掛尊之用，臂線由尊筆自續）─────────────────────────────
function 拳持拳(bi, x, z, 比, 直指, 飾 = true) {
    const s = 手勢(bi, x, z, 比);
    const 簡 = !飾 && Math.abs(比) < 1.5; // 掛尊小比：裹指三列、紋略（線少形存）
    // 真相（依像不依訛，2026-07-05 主人校）：右拳**包**左頭指——兩拳相合如一，
    // 頭指沒於右拳之中，惟尖微露拳頂，右拇端拄之。無「隙中露節」之事。
    // 下拳（左）：先蔽後勒——背向前，頂與上拳相接（上拳後落而蔽其接）
    s.蔽([[-2.85, 0.9], [-3.1, 2.2], [-2.7, 3.4], [-1.5, 3.95], [0, 4.6], [1.95, 4.2],
        [2.7, 3.3], [3.15, 2.4], [3.0, 1.4], [2.6, 0.75], [1.4, 0.35], [0, 0.35], [-1.6, 0.4]]);
    s.骨(() => {
        s.M(-2.85, 0.9);
        s.C(-3.1, 2.2, -2.7, 3.4, -1.5, 3.95);
        s.C(-0.1, 4.6, 1.95, 4.2, 2.7, 3.3);
        s.C(3.15, 2.4, 3.0, 1.4, 2.6, 0.75);
        s.S();
        s.M(2.6, 0.75);
        s.Qk(1.4, 0.32, 0, 0.32);
        s.Qk(-1.6, 0.38, -2.85, 0.9);
        s.S();
    });
    // 下拳（左）四指：金剛拳自背觀——本節之背自脊而下，急屈內折入掌（短塊非長柱）
    s.衣(() => {
        const 大圖 = Math.abs(比) >= 2;
        for (const kx of [-1.9, -0.68, 0.68, 1.9]) {
            const 鏈 = s.指(kx, 1.35, Math.PI / 2 - 0.04 * Math.sign(kx), [1.0, 0.72], [0, 0.95]);
            s.畫(鏈, 0.94, 0.82, { 紋: true, 斂: true });
        }
        // 指根之脊：本節之列（拳上緣一橫脊）
        s.細(() => { s.M(-2.25, 1.3); s.C(-0.9, 1.0, 0.9, 1.0, 2.3, 1.3); s.S(); });
        // 蜷指之界：末節內折沒入掌之一橫（畫其可見之折）
        s.細(() => { s.M(-1.95, 2.6); s.C(-0.7, 2.9, 0.9, 2.9, 2.05, 2.65); s.S(); });
        if (直指 === '頭') {
            // 左拇：縱傍拳左緣，梢抵上拳之底（兩拳相接之證）
            const 拇 = s.指(-2.55, 1.9, -Math.PI / 2 + 0.18, [1.3, 1.05], [0, -0.12]);
            s.畫(拇, 指寬.拇根, 指寬.拇梢, { 紋: true, 甲: 大圖 });
        }
    });
    // 上拳（右）：先蔽後勒——直坐於下拳之上（兩拳相合如一），四指裹左頭指於掌中
    s.蔽([[-3.0, -0.1], [-3.3, -1.4], [-3.1, -3.0], [-2.3, -4.0], [-1.2, -5.05], [1.4, -5.1],
        [2.5, -4.35], [3.35, -3.7], [3.4, -2.2], [3.05, -1.1], [2.7, -0.1], [1.6, 0.5],
        [0.3, 0.55], [-1.5, 0.55]]);
    s.骨(() => {
        s.M(-3.0, -0.1);
        s.C(-3.3, -1.4, -3.1, -3.0, -2.3, -4.0);
        s.C(-1.2, -5.05, 1.4, -5.1, 2.5, -4.35);
        s.C(3.35, -3.7, 3.4, -2.2, 3.05, -1.1);
        s.C(2.7, -0.1, 1.6, 0.5, 0.3, 0.55);
        s.Qk(-1.5, 0.55, -3.0, -0.1);
        s.S();
    });
    s.衣(() => {
        // 裹指四指：自下而上（右小→無名→中→頭）橫裹——逐指分明之塊，
        //   鋒脊（本節之列）朝前成橫段，梢向掌心微屈而斂
        const 大圖 = Math.abs(比) >= 2;
        const 列z = 簡 ? [-0.85, -2.05, -3.3] : [-0.75, -1.75, -2.75, -3.7];
        const 寬 = 簡 ? [1.0, 1.06, 0.92] : [0.9, 1.02, 1.02, 0.88];
        for (let i = 0; i < 列z.length; i++) {
            const 鏈 = s.指(2.3, 列z[i], Math.PI - 0.06, [1.5, 1.2], [0, 0.5]);
            s.畫(鏈, 寬[i], 寬[i] * 0.86, { 紋: true, 甲: 大圖, 斂: true });
        }
        // 鋒脊：四指本節之列（拳右緣一豎脊，貫四指之根）
        s.細(() => { s.M(2.45, -0.55); s.C(2.7, -1.5, 2.65, -2.9, 2.3, -3.85); s.S(); });
        if (直指 === '頭') {
            // 左頭指之尖：微露於拳頂（沒於拳中，惟尖出）
            const 尖 = s.指(0.15, -4.55, -Math.PI / 2 - 0.06, [0.85], []);
            s.畫(尖, 0.88, 0.7, { 紋: false });
            // 右大指：自鋒脊上斜覆拳頂，端拄左頭指之尖——一杆而抵
            const 拇 = s.指(2.55, -3.75, Math.PI - 0.55, [1.6, 1.3], [0, -0.4]);
            s.畫(拇, 指寬.拇根, 指寬.拇梢, { 紋: true, 甲: 大圖 });
        }
        else {
            // 如來拳：左拇全沒於右拳（尖不露），右拇自斜覆其前
            const 拇 = s.指(2.55, -3.55, Math.PI - 0.6, [1.65, 1.35], [0, -0.32]);
            s.畫(拇, 指寬.拇根, 指寬.拇梢, { 紋: true, 甲: Math.abs(比) >= 2 });
        }
    });
    // 小臂（掛尊則略，臂由尊筆自續）：左腕自左下承下拳，右腕自右橫承上拳——
    // 掌臂相接杆意一貫（主人之訓）
    if (飾) {
        s.骨(() => {
            s.M(-2.75, 1.5);
            s.C(-3.9, 2.6, -4.9, 3.9, -5.6, 5.3);
            s.S();
            s.M(-0.9, 4.35);
            s.C(-2.0, 5.0, -3.2, 5.8, -4.2, 6.6);
            s.S();
            s.M(3.3, -3.5);
            s.C(4.5, -3.6, 5.7, -3.5, 6.8, -3.2);
            s.S();
            s.M(3.1, -1.05);
            s.C(4.3, -0.9, 5.5, -0.75, 6.6, -0.45);
            s.S();
        });
        s.細(() => {
            s.M(-3.7, 4.05);
            s.Qk(-4.35, 4.75, -4.55, 5.75);
            s.S();
            s.M(5.5, -3.45);
            s.Qk(5.85, -2.4, 5.6, -0.85);
            s.S();
        });
    }
}
// 如來拳：左蓮華拳豎大指，右金剛拳握之（右上左下）
export function 如來拳(bi, x, z, 比 = 1) {
    拳持拳(bi, x, z, 比, '拇');
}
// ═══ 常用九印 ════════════════════════════════════════════════════════════════
// 智拳印：左金剛拳獨豎頭指，右金剛拳握之，右大指端拄左頭指端
// （左頭指沒於右拳惟尖微露；「右小指握」與「隙中露節」二坊說皆訛勿從）
export function 智拳印(bi, x, z, 比 = 1, 飾 = true) {
    拳持拳(bi, x, z, 比, '頭', 飾);
}
// ── 定印之基：兩手仰疊右上左下，二拇相拄成卵（法界定印／彌陀定印共之）
//    飾＝false 則略腕（掛尊之用，臂線由尊筆自續）─────────────────────────────
function 定印基(bi, x, z, 比, 品, 飾 = true) {
    const s = 手勢(bi, x, z, 比);
    // 簡門：**掛尊**（飾=false）而小比之時，指列去其小指、紋皆略——線少而形存；
    // 獨立成譜（飾=true）雖比小亦全繪（Codex 六審之疵：勿改預設之繪）
    const 簡 = !飾 && Math.abs(比) < 1.5;
    // 遮擋之序：下手（左）先落，上手（右）後落而蔽之，二拇最前
    // 下手（左）掌郭：指向右，腕在左（右手覆其上，見其左半）
    s.骨(() => {
        s.M(-2.7, 0.6);
        s.C(-3.7, 0.35, -4.6, 0.5, -5.1, 1.05);
        s.S();
        s.M(-2.15, 2.9);
        s.C(-3.3, 3.3, -4.4, 3.2, -5.0, 2.6);
        s.S();
    });
    s.細(() => { s.M(-5.15, 1.15); s.Qk(-5.45, 1.9, -5.05, 2.5); s.S(); });
    // 下手四指：對向四列（隱於上手之蔭，紋略）
    const 下列 = [
        [-1.7, 1.3, [1.35, 1.0, 0.7], 指寬.小根, 指寬.小梢, false],
        [-1.85, 1.85, [1.7, 1.28, 0.9], 指寬.根, 指寬.梢, false],
        [-1.95, 2.45, [1.9, 1.4, 1.0], 指寬.根, 指寬.梢, false],
        [-1.95, 3.05, [1.7, 1.28, 0.9], 0.92, 0.70, true],
    ];
    s.衣(() => {
        for (const [根a, 根b, 長, w0, w1, 頭] of 下列) {
            if (品 && 頭)
                continue;
            if (簡 && w0 === 指寬.小根)
                continue;
            const 鏈 = s.指(根a, 根b, 0, 長, [0, 0.05, 0.06]);
            s.畫(鏈, w0, w1, { 紋: false });
        }
    });
    // 上手（右）掌郭：指向左，腕在右；掌碗有底（蔽下手之相疊處）
    s.蔽([[1.75, -1.8], [2.9, -2.05], [4.1, -1.9], [4.85, -1.3], [5.1, -0.45], [4.85, 0.45],
        [4.15, 0.95], [3.0, 1.0], [1.9, 0.6]]);
    s.骨(() => {
        s.M(1.75, -1.8);
        s.C(2.9, -2.05, 4.1, -1.9, 4.85, -1.3);
        s.S();
        s.M(1.9, 0.6);
        s.C(3.0, 1.0, 4.15, 0.95, 4.85, 0.45);
        s.S();
    });
    s.細(() => { s.M(4.92, -1.22); s.Qk(5.22, -0.45, 4.92, 0.38); s.S(); });
    // 上手四指：橫臥四列（上小下頭），微垂（梢斂讓二拇之弧）
    const 上列 = [
        [1.7, -1.55, [1.35, 1.0, 0.7], 指寬.小根, 指寬.小梢, false],
        [1.85, -1.0, [1.7, 1.28, 0.9], 指寬.根, 指寬.梢, false],
        [1.95, -0.4, [1.9, 1.4, 1.0], 指寬.根, 指寬.梢, false],
        [1.95, 0.25, [1.7, 1.28, 0.9], 0.92, 0.70, true],
    ];
    s.衣(() => {
        for (const [根a, 根b, 長, w0, w1, 頭] of 上列) {
            if (品 && 頭)
                continue; // 彌陀定印：頭指起而捻拇
            if (簡 && w0 === 指寬.小根)
                continue;
            const 鏈 = s.指(根a, 根b, Math.PI, 長, [0, -0.05, -0.06]);
            s.畫(鏈, w0, w1, { 紋: !簡 });
        }
    });
    // 二大指：仰起相就，端相拄於頂心成卵（定印）；或各捻頭指成雙環（彌陀上品）
    s.衣(() => {
        if (!品) {
            const 左拇 = s.指(-3.2, 0.85, -0.55, [1.7, 1.35, 1.0], [0, -0.4, -0.5]);
            s.畫(左拇, 指寬.拇根, 指寬.拇梢, { 紋: true, 甲: Math.abs(比) >= 2 });
            const 右拇 = s.指(3.2, 0.8, Math.PI + 0.55, [1.7, 1.35, 1.0], [0, 0.4, 0.5]);
            s.畫(右拇, 指寬.拇根, 指寬.拇梢, { 紋: true, 甲: Math.abs(比) >= 2 });
        }
        else {
            const 左拇 = s.指(-3.2, 0.85, -0.6, [1.7, 1.4], [0, -0.3]);
            s.畫(左拇, 指寬.拇根, 指寬.拇梢, { 紋: true, 甲: Math.abs(比) >= 2 });
            const 右拇 = s.指(3.2, 0.8, Math.PI + 0.6, [1.7, 1.4], [0, 0.3]);
            s.畫(右拇, 指寬.拇根, 指寬.拇梢, { 紋: true, 甲: Math.abs(比) >= 2 });
            // 頭指起而捻之：左右各成一環
            const 左頭 = s.指(-1.95, 3.05, -1.3, [1.55, 1.25, 0.9], [0, 0.1, 0.35]);
            s.畫(左頭, 0.92, 0.70, { 紋: true });
            const 右頭 = s.指(1.95, 0.25, Math.PI + 1.35, [1.2, 0.95, 0.7], [0, -0.15, -0.45]);
            s.畫(右頭, 0.92, 0.70, { 紋: true });
        }
    });
    // 腕：順掌勢而出，端開向畫外
    if (飾)
        s.骨(() => {
            s.M(4.88, -1.28);
            s.L(6.0, -1.5);
            s.S();
            s.M(4.88, 0.5);
            s.L(6.0, 0.68);
            s.S();
            s.M(-5.05, 1.0);
            s.L(-6.15, 0.82);
            s.S();
            s.M(-4.95, 2.65);
            s.L(-6.05, 2.85);
            s.S();
        });
}
// 法界定印：兩手仰疊右上左下，二大指端相拄成橢圓
export function 法界定印(bi, x, z, 比 = 1, 飾 = true) {
    定印基(bi, x, z, 比, false, 飾);
}
// 彌陀定印：基形同定印，大指捻頭指成雙環（上品之式；九品晚出，出典欄必注）
export function 彌陀定印(bi, x, z, 比 = 1, 飾 = true) {
    定印基(bi, x, z, 比, true, 飾);
}
// ── 掌立之基：立掌向外（施無畏上／與願下）；飾＝false 則略腕（掛尊之用）──────
function 掌立(bi, x, z, 比, 向, 飾 = true) {
    const σ = 向 === '上' ? 1 : -1;
    const s = 手勢(bi, x, z, 比 * σ); // 比負＝點對稱旋半周：上式一稿兩用
    // 掌郭：右緣拇丘、左緣小指丘（右手掌向外，拇在右）
    s.骨(() => {
        s.M(-1.6, 4.55);
        s.C(-2.45, 3.3, -2.6, 1.6, -2.1, -1.3);
        s.S();
        s.M(1.5, 4.6);
        s.C(2.5, 3.6, 2.8, 2.5, 2.62, 1.35);
        s.S();
        s.M(2.42, 0.5);
        s.Qk(2.25, -0.6, 1.98, -1.4);
        s.S();
    });
    // 五指：舒伸微扇（頭指之側拇指開）
    const 目 = [
        [1.65, -1.5, 0.10, [1.9, 1.4, 1.02], 0.92, 0.70],
        [0.55, -1.68, 0.02, [2.15, 1.6, 1.16], 指寬.根, 指寬.梢],
        [-0.55, -1.62, -0.05, [2.0, 1.5, 1.08], 指寬.根, 指寬.梢],
        [-1.6, -1.42, -0.15, [1.6, 1.15, 0.85], 指寬.小根, 指寬.小梢],
    ];
    s.衣(() => {
        for (const [根a, 根b, 斜, 長, w0, w1] of 目) {
            const 鏈 = s.指(根a, 根b, -Math.PI / 2 + 斜, 長, [0, 斜 * 0.5, 斜 * 0.6]);
            s.畫(鏈, w0, w1, { 紋: true });
        }
        // 拇指：自拇丘開張
        const 拇 = s.指(2.5, 1.25, -Math.PI / 2 + 0.58, [2.0, 1.62], [0, -0.18]);
        s.畫(拇, 指寬.拇根, 指寬.拇梢, { 紋: true, 甲: Math.abs(比) >= 2 });
    });
    // 指丫：根間三谷
    s.細(() => {
        for (const [ya, yb] of [[1.1, -1.5], [0.0, -1.6], [-1.08, -1.45]])
            s.弧(ya, yb, 0.22, Math.PI * 1.1, Math.PI * 1.9);
    });
    // 掌之丘壑：三紋收於掌內，不犯拇丘（名从俗，線依犍陀羅之工）
    s.細(() => {
        s.M(-2.0, -0.9);
        s.C(-0.9, -1.35, 0.5, -1.45, 1.42, -1.2);
        s.S();
        s.M(1.55, -0.35);
        s.C(0.6, -0.05, -0.6, 0.15, -1.7, 0.55);
        s.S();
        s.M(1.5, -0.7);
        s.C(1.45, 0.7, 1.1, 2.1, 0.45, 3.2);
        s.S();
    });
    // 腕
    if (飾) {
        s.骨(() => { s.M(-1.65, 4.6); s.L(-1.95, 5.75); s.S(); s.M(1.55, 4.65); s.L(1.8, 5.8); s.S(); });
        s.細(() => { s.M(-1.4, 4.85); s.Qk(0, 5.25, 1.35, 4.9); s.S(); });
    }
}
// 施無畏印：屈臂上舉，掌向外五指舒伸
export function 施無畏印(bi, x, z, 比 = 1, 飾 = true) {
    掌立(bi, x, z, 比, '上', 飾);
}
// 與願印：掌向外五指舒展下垂
export function 與願印(bi, x, z, 比 = 1, 飾 = true) {
    掌立(bi, x, z, 比, '下', 飾);
}
// 觸地印：右手覆膝，五指垂而指端觸地（左手仰臍前——此譜錄觸地之右手）
export function 觸地印(bi, x, z, 比 = 1, 飾 = true) {
    const s = 手勢(bi, x, z, 比);
    // 背之蔽：掛尊時膝腿之線斷於掌背（手在腿前）
    s.蔽([[-2.0, -4.3], [1.3, -4.5], [2.05, -2.5], [2.05, -0.6], [1.5, 0.35],
        [-0.6, 0.5], [-1.75, 0.2], [-2.5, -1.5], [-2.45, -3.2]]);
    // 背郭：腕自左上來——尺緣一杆直入小指之根，拇緣一杆直入拇根（氣韻連貫之律）
    s.骨(() => {
        s.M(-2.05, -4.35);
        s.C(-2.5, -3.0, -2.55, -1.5, -2.07, -0.22);
        s.S();
        s.M(1.35, -4.55);
        s.C(1.85, -3.5, 2.08, -2.5, 2.0, -1.6);
        s.S();
    });
    // 掌骨之腱：背上淡扇（愈淡愈遠）
    s.細(() => bi.dim(0.55, () => {
        s.M(-0.2, -3.3);
        s.C(-0.5, -2.0, -0.7, -0.9, -0.78, -0.15);
        s.S();
        s.M(0.45, -3.2);
        s.C(0.4, -2.0, 0.35, -0.9, 0.32, -0.2);
        s.S();
    }));
    // 掌骨之峰：四丘（淡而伏脊）
    s.細(() => bi.dim(0.6, () => {
        for (const [ka, kb] of [[-1.72, -0.25], [-0.6, 0.05], [0.5, 0.0], [1.45, -0.3]])
            s.弧(ka, kb, 0.27, Math.PI * 1.15, Math.PI * 1.88);
    }));
    // 四指：垂而觸地——梢弧相和（中最深），節節有屈而不僵
    const 目 = [
        [1.45, -0.2, -0.03, [1.95, 1.45, 1.02], [0, 0.06, 0.09], 0.92, 0.70],
        [0.5, 0.12, 0.0, [2.1, 1.56, 1.1], [0, 0.07, 0.11], 指寬.根, 指寬.梢],
        [-0.6, 0.15, 0.04, [1.95, 1.45, 1.02], [0, 0.09, 0.13], 指寬.根, 指寬.梢],
        [-1.68, -0.18, 0.1, [1.58, 1.15, 0.82], [0, 0.12, 0.16], 指寬.小根, 指寬.小梢],
    ];
    s.衣(() => {
        for (const [根a, 根b, 斜, 長, 屈, w0, w1] of 目) {
            const 鏈 = s.指(根a, 根b, Math.PI / 2 + 斜, 長, 屈);
            s.畫(鏈, w0, w1, { 紋: true, 甲: Math.abs(比) >= 2 });
        }
        // 大指：承拇緣之杆垂而內顧
        const 拇 = s.指(1.9, -1.5, Math.PI / 2 - 0.32, [1.8, 1.5], [0, 0.38]);
        s.畫(拇, 指寬.拇根, 指寬.拇梢, { 紋: true, 甲: Math.abs(比) >= 2 });
    });
    if (飾) {
        // 地線：指端所觸（金剛座之地）
        s.細(() => { s.M(-3.1, 4.72); s.Qk(0, 4.6, 3.2, 4.72); s.S(); });
        // 腕：自左上來，二線相隨
        s.骨(() => { s.M(-2.02, -4.42); s.L(-2.55, -5.6); s.S(); s.M(1.32, -4.58); s.L(1.0, -5.72); s.S(); });
        s.細(() => { s.M(-1.6, -4.85); s.Qk(-0.45, -5.25, 0.7, -5.05); s.S(); });
    }
}
// ── 捻掌：拇頭相捻成環之立掌（說法印之半） ───────────────────────────────────
// 面：'掌'＝掌向觀者（見掌紋）；'背'＝背向觀者（見甲與腱）
function 捻掌(bi, x, z, 比, 鏡, 面) {
    const s = 手勢(bi, x, z, 比, 鏡);
    // 掌郭
    s.骨(() => {
        s.M(-1.55, 4.0);
        s.C(-2.3, 2.9, -2.45, 1.4, -2.0, -1.1);
        s.S();
        s.M(1.45, 4.05);
        s.C(2.35, 3.1, 2.6, 2.15, 2.5, 1.2);
        s.S();
    });
    // 三指舒伸（中無名小），微扇
    const 目 = [
        [0.5, -1.45, -0.04, [2.1, 1.56, 1.12], 指寬.根, 指寬.梢],
        [-0.55, -1.4, -0.12, [1.95, 1.45, 1.02], 指寬.根, 指寬.梢],
        [-1.5, -1.2, -0.22, [1.58, 1.14, 0.82], 指寬.小根, 指寬.小梢],
    ];
    s.衣(() => {
        for (const [根a, 根b, 斜, 長, w0, w1] of 目) {
            const 鏈 = s.指(根a, 根b, -Math.PI / 2 + 斜, 長, [0, 斜 * 0.5, 斜 * 0.6]);
            s.畫(鏈, w0, w1, { 紋: true, 甲: 面 === '背' && Math.abs(比) >= 2 });
        }
        // 頭指：自根俯而下就，梢止於拇端之上——環自虛處生，不使線結
        const 頭 = s.指(1.6, -1.2, 1.95, [1.45, 1.05, 0.72], [0, 0.5, 0.5]);
        s.畫(頭, 0.92, 0.70, { 紋: true });
        // 拇指：自拇丘斜上迎之，端與頭指端相就成環
        const 拇 = s.指(2.4, 1.5, -2.6, [1.75, 1.3], [0, -0.25]);
        s.畫(拇, 指寬.拇根, 指寬.拇梢, { 紋: false, 甲: Math.abs(比) >= 2 });
    });
    // 面相之異：掌見紋，背見腱
    s.細(() => {
        if (面 === '掌') {
            s.M(-1.8, -0.7);
            s.C(-0.8, -1.05, 0.3, -1.1, 1.1, -0.9);
            s.S();
            s.M(1.75, -0.2);
            s.C(0.7, 0.1, -0.5, 0.3, -1.5, 0.7);
            s.S();
        }
        else {
            s.M(-0.3, 2.6);
            s.C(-0.35, 1.5, -0.3, 0.4, -0.15, -0.6);
            s.S();
            s.M(0.55, 2.7);
            s.C(0.6, 1.6, 0.7, 0.5, 0.9, -0.5);
            s.S();
        }
    });
    // 腕
    s.骨(() => { s.M(-1.6, 4.05); s.L(-1.9, 5.2); s.S(); s.M(1.5, 4.1); s.L(1.75, 5.25); s.S(); });
    s.細(() => { s.M(-1.35, 4.3); s.Qk(0, 4.7, 1.3, 4.35); s.S(); });
}
// 說法印：兩手當胸，大指頭指相捻成環，左內右外相對（捻中指亦有其式）
export function 說法印(bi, x, z, 比 = 1) {
    捻掌(bi, x - 3.0 * 比, z + 0.55 * 比, 比, -1, '背'); // 左手掌內（背向觀者）
    捻掌(bi, x + 3.0 * 比, z - 0.55 * 比, 比, 1, '掌'); // 右手掌外
}
// 期剋印：金剛拳豎頭指如鈎（tarjanī，威嚇鈎召；或並豎小指作二鈎）
export function 期剋印(bi, x, z, 比 = 1) {
    拳基(bi, x, z, 比, { 拇: '壓', 豎頭: true, 鈎: 0.8 });
}
